def rx(h,c,t=60):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=10','root@'+h,c],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()
def pct_e(id,c,t=120):
    r=subprocess.run(['ssh','-o','StrictHostKeyChecking=no','-o','ConnectTimeout=10','root@'+P1,'pct exec '+str(id)+' -- bash -c '+json.dumps(c)],capture_output=True,text=True,timeout=t)
    return (r.stdout+r.stderr).strip()
def save(e):
    try: open(MP,'a').write('\n### CT108 v5 ['+TSF+']\n'+e+'\n')
    except: pass
print('='*55)
print('CT108 FINAL DEPLOY v5')
print(TSF)
print('='*55)

# CT108 check
st=rx(P1,'pct status 108')
print('[1] CT108:',st)
if 'stopped' in st.lower():
    rx(P1,'pct start 108',t=20);time.sleep(8)

# Backup
pct_e(108,f'cp {WEB}/dashboard.html {WEB}/dashboard.html.bak_{TSF} 2>/dev/null || true')
rx(P1,f'mkdir -p /root/ct108_backups && pct pull 108 {WEB}/dashboard.html /root/ct108_backups/dash_{TSF}.html 2>/dev/null || true',t=20)
