# Test site accessibility
import urllib.request
for scheme in ['https','http']:
    try:
        req=urllib.request.Request(scheme+'://vntworld.com/dashboard.html',headers={'User-Agent':'VNT/1.0'})
        with urllib.request.urlopen(req,timeout=10) as r:
            size=len(r.read())
            print(f'[9] {scheme}://vntworld.com: OK ({size} bytes)')
            break
    except Exception as e:
        print(f'[9] {scheme}://vntworld.com: {str(e)[:60]}')

